        tokens = model.to_tokens(text, prepend_bos=True)
        if tokens.shape[1] >= seq_len:
            sequences.append(tokens[:, :seq_len])
        if len(sequences) >= n_sequences:
            break

    print(f"Loaded {len(sequences)} naturalistic sequences of length {seq_len}")
    return sequences

